BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?dep ?client ?supplier WHERE {
  ?dep rdf:type vocab:dependency .
  OPTIONAL { ?dep vocab:Dependency_client ?client }
  OPTIONAL { ?dep vocab:Dependency_supplier ?supplier }
}
LIMIT 5

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type WHERE {
  VALUES ?elem { <http://api.koneksys.com/cameo/TMT/component/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::09%20Views::TMT-APS-SE::TMT-APS%20Site%20Characterization> }
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 10
